"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[8249],{3964:(e,n,t)=>{t.r(n),t.d(n,{assets:()=>c,contentTitle:()=>r,default:()=>u,frontMatter:()=>s,metadata:()=>i,toc:()=>d});const i=JSON.parse('{"id":"training/part1-foundations/executive-summary","title":"1. Executive Summary","description":"On June 30, 2026, the RSA Professional Services team conducted Day 1 of a multi-day technical enablement session on the RSA Prime solution suite. The day was delivered in two recorded segments: a morning-through-afternoon session of approximately 3 hours 19 minutes (Part 1) and a 26-minute end-of-day continuation (Part 2) focused on the Bulk Update tool.","source":"@site/docs/training/part1-foundations/1-executive-summary.md","sourceDirName":"training/part1-foundations","slug":"/training/part1-foundations/executive-summary","permalink":"/rsapsdocumentation/docs/training/part1-foundations/executive-summary","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"title":"1. Executive Summary","sidebar_position":1},"sidebar":"docsSidebar","previous":{"title":"Welcome to PrimeTime","permalink":"/rsapsdocumentation/docs/"},"next":{"title":"2. Session Logistics, Participants, and Structure","permalink":"/rsapsdocumentation/docs/training/part1-foundations/session-logistics-participants-and-structure"}}');var a=t(4848),o=t(8453);const s={title:"1. Executive Summary",sidebar_position:1},r="1. Executive Summary",c={},d=[];function l(e){const n={h1:"h1",header:"header",li:"li",p:"p",ul:"ul",...(0,o.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.header,{children:(0,a.jsx)(n.h1,{id:"1-executive-summary",children:"1. Executive Summary"})}),"\n",(0,a.jsx)(n.p,{children:"On June 30, 2026, the RSA Professional Services team conducted Day 1 of a multi-day technical enablement session on the RSA Prime solution suite. The day was delivered in two recorded segments: a morning-through-afternoon session of approximately 3 hours 19 minutes (Part 1) and a 26-minute end-of-day continuation (Part 2) focused on the Bulk Update tool."}),"\n",(0,a.jsx)(n.p,{children:"The overarching objective of Day 1 was to bring the consulting team from conceptual familiarity with Prime to genuine operational fluency: understanding what the Prime application suite contains, how it is packaged and installed via PrimeKit and Prime Quick Setup, how it is architected in production, how it is configured through its XML and properties files, and how its most consequential field capabilities \u2014 the rotating-password service account system, self-service enrollment protection, and Windows Password Integration (WPI) automation \u2014 actually work under the hood. The session blended slide-driven instruction with an extensive live demonstration in which a complete Prime environment was installed, connected to both RSA Authentication Manager and the Cloud Authentication Service, and exercised end-to-end via REST API calls in Postman."}),"\n",(0,a.jsx)(n.p,{children:"A defining feature of the day was its practitioner orientation. Throughout the session the trainer and attendees repeatedly connected the material to live federal engagements \u2014 including an upcoming SOCOM onsite where WPI-driven password rotation is the customer's primary use case \u2014 and to the unique operational constraints of classified (SCIF) environments, where standard troubleshooting workflows (log export, screen sharing, remote support) are unavailable and consultants must rely on parallel lab reproduction, printed documentation, and iterative site visits."}),"\n",(0,a.jsx)(n.p,{children:"Key outcomes and themes from Day 1 include:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsx)(n.li,{children:"Prime is a suite, not a product. Beyond the three core web applications (MS/AMS, SSP, HTAP), Prime encompasses bulk administration tools, the Prime Central Authentication Portal (PCAP), the Virtual Token Service (VTS), and the Expiry Notification Service (ENS) \u2014 all of which evolve rapidly in response to specific customer requests."}),"\n",(0,a.jsx)(n.li,{children:"Installation has been radically compressed. What historically took weeks to months of manual configuration now takes under 30 minutes with PrimeKit and Prime Quick Setup, provided the Authentication Manager and Cloud prerequisites are prepared in advance."}),"\n",(0,a.jsx)(n.li,{children:"Configuration is where the real work lives. Prime deliberately has no administrative UI; all behavior is governed by XML and properties files. This design choice accelerates feature delivery but means consultant value is concentrated in configuration, customization, and troubleshooting."}),"\n",(0,a.jsx)(n.li,{children:"Session token architecture drives clustering design. Because MS session tokens are in-memory and node-specific, multi-node deployments require either load-balancer session persistence or Prime's auth clustering mechanism (machine IDs with a mod-20 encoding), with Redis-backed clustering now supported for containerized deployments."}),"\n",(0,a.jsx)(n.li,{children:"The service account system solves machine-to-machine credential rotation. A purpose-built mechanism issues a new password in the API response every configurable interval (25 days in the demo), tracked via an encrypted identity attribute in Authentication Manager."}),"\n",(0,a.jsx)(n.li,{children:"Bulk Update is the linchpin of the federal WPI use case. The standalone Java command-line tool rotates Active Directory passwords for group members on a schedule and synchronizes the Windows Password Integration cache in Authentication Manager, enabling effectively passwordless operation in environments with mandatory password rotation policies."}),"\n",(0,a.jsx)(n.li,{children:"Compliance documentation is an emerging gap and opportunity. The team identified STIG-style hardening evidence and audit-ready reporting as areas where PS can add differentiated value for federal customers."}),"\n"]})]})}function u(e={}){const{wrapper:n}={...(0,o.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(l,{...e})}):l(e)}},8453:(e,n,t)=>{t.d(n,{R:()=>s,x:()=>r});var i=t(6540);const a={},o=i.createContext(a);function s(e){const n=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),i.createElement(o.Provider,{value:n},e.children)}}}]);